import scala.xml._
import scala.util.{Try, Success, Failure}
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer

case class ConfigSettings(setting1: String, setting2: String)

object XmlConfigService {
  
  def parseXmlConfig(xmlString: String): Try[ConfigSettings] = {
    Try {
      val xml = XML.loadString(xmlString)
      val setting1 = (xml \\ "setting1").text
      val setting2 = (xml \\ "setting2").text
      ConfigSettings(setting1, setting2)
    }
  }

  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("xml-config-service")
    implicit val materializer = ActorMaterializer()
    implicit val executionContext = system.dispatcher

    val route =
      path("parse-config") {
        post {
          entity(as[String]) { xmlString =>
            parseXmlConfig(xmlString) match {
              case Success(config) =>
                complete(HttpEntity(ContentTypes.`application/json`, s"""{"setting1":"${config.setting1}","setting2":"${config.setting2}"}"""))
              case Failure(ex) =>
                complete(StatusCodes.BadRequest, s"Failed to parse XML: ${ex.getMessage}")
            }
          }
        }
      }

    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    
    println("Server online at http://localhost:8080/\nPress RETURN to stop...")
    scala.io.StdIn.readLine()
    bindingFuture
      .flatMap(_.unbind())
      .onComplete(_ => system.terminate())
  }
}